## 3️⃣ The fix – two possible approaches  

### A️⃣ Use the SDK‑provided `pricePerMonthString` (recommended)

```ts
// revenueCat.ts
export const mapPackageToPaywallCard = (pkg: Package): PaywallCard => {
  const isAnnual = pkg.product.subscriptionPeriod?.unit === 'year';

  return {
    // "$79.99/yr" or "$9.99/mo"
    price: `${pkg.product.priceString}${isAnnual ? '/yr' : '/mo'}`,

    // Use the SDK‑provided per‑month string if it exists,
    // otherwise fall back to a manual calculation.
    pricePerMonth:
      pkg.product.pricePerMonthString ??
      // manual fallback (see section B)
      `${(parseFloat(pkg.product.priceString.replace(/[^\d.]/g, '')) /
        (isAnnual ? 12 : 1)
      ).toFixed(2)}`,
  };
};
```

### B️⃣ Compute the per‑month price yourself (if you can’t rely on `pricePerMonthString`)

```ts
function computeMonthlyPrice(
  priceString: string,
  periodUnit: 'day' | 'week' | 'month' | 'year',
  periodValue: number = 1,
): string {
  const raw = parseFloat(priceString.replace(/[^\d.]/g, ''));
  let months: number;

  switch (periodUnit) {
    case 'day':
      months = (periodValue / 30);
      break;
    case 'week':
      months = (periodValue * 7) / 30;
      break;
    case 'month':
      months = periodValue;
      break;
    case 'year':
      months = periodValue * 12;
      break;
    default:
      months = 1;
  }

  const perMonth = raw / months;
  return perMonth.toLocaleString(undefined, {
    style: 'currency',
    currency: priceString.replace(/[0-9.,\s]/g, ''), // keep the symbol
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
}

// In the mapper
return {
  price: `${pkg.product.priceString}${isAnnual ? '/yr' : '/mo'}`,
  pricePerMonth: computeMonthlyPrice(
    pkg.product.priceString,
    pkg.product.subscriptionPeriod?.unit ?? 'month',
    pkg.product.subscriptionPeriod?.value ?? 1,
  ),
};
```

Both approaches guarantee that `pricePerMonth` contains the **monthly equivalent** (`$6.67` for a $79.99/yr plan).

